// Icône d'app officielle Beebs — source: iTunes Lookup API (Apple), artworkUrl512,
// app id 1457130269. Encodée en base64 pour rester inline (pas de fichier externe chargé
// au runtime).
const DATA_URI = "data:image/png;base64,";

export default function BeebsIcon({ size = 24, radius }) {
  const r = radius ?? Math.round(size * 0.28);
  return (
    <img
      src={DATA_URI}
      alt="Beebs"
      width={size}
      height={size}
      style={{ width: size, height: size, borderRadius: r, display: "block", objectFit: "cover" }}
    />
  );
}
